/**
 * One-off generator: writes case-study-hikr-cohort-aggregate.sql
 * Run: node scripts/sql/generate-case-study-cohort-sql.js
 */
const fs = require("fs");
const path = require("path");

const pct = (cond) =>
  `  round((100.0 * count(*) FILTER (WHERE ${cond}) / nullif(count(*), 0))::numeric, 4)::text`;
const mx = (expr) => `  max(${expr})`;
const p95 = (expr) => `  percentile_cont(0.95) WITHIN GROUP (ORDER BY ${expr})`;

const parts = [];

