parts.push(`,`);
parts.push(`${mx("sm.insertion_relative_threshold")} AS max_sm_insertion_relative_threshold`);
parts.push(`,`);
parts.push(`${p95("sm.insertion_relative_threshold")} AS p95_sm_insertion_relative_threshold`);
parts.push(`,`);
parts.push(`${mx("sm.sorted_cluster_count")} AS max_sm_sorted_cluster_count`);
parts.push(`,`);
